const query = $json.query || {};
const body = $json.body || $json;
const message = query.message || body.message || body.goal || '';
const projectId = query.project_id || body.project_id || ('proj-' + Date.now());
const reference_url = query.reference_url || body.reference_url || null;
const image_data = body.image_data || null;
return [{ json: { message, project_id: projectId, operation: 'init', goal: message, reference_url, image_data } }];

const operation = $json.operation || 'get';
const projectId = $json.project_id;
if (!projectId) return [{ json: { error: 'project_id required' } }];
const store = $getWorkflowStaticData('global');
if (operation === 'init') {
  if (store[projectId]) return [{ json: { ...store[projectId], already_exists: true } }];
  store[projectId] = {
    project_id: projectId,
    goal: $json.goal || '',
    status: 'active',
    completed_tasks: [],
    pending_tasks: [],
    files: [],
    created_at: new Date().toISOString(),
    last_updated: new Date().toISOString()
  };
  return [{ json: store[projectId] }];
}
if (operation === 'get') {
  return [{ json: store[projectId] || { project_id: projectId, exists: false } }];
}
if (operation === 'set') {
  const existing = store[projectId] || {};
  store[projectId] = { ...existing, ...$json.state, project_id: projectId, last_updated: new Date().toISOString() };
  return [{ json: store[projectId] }];
}
return [{ json: { error: `Unknown operation: ${operation}` } }];

// MODIFIED: Absorbs Research: Build Project Context
// Caches _allFileContents, _researchDocs, _projectFileList in static data
// so Phase 2 chunks don't need to re-fetch or re-compute.
const memory = $('Init Memory').first().json;
const message = $('Extract Input').first().json.message;
const allFiles = $json.files || [];
const staticData = $getWorkflowStaticData('global');

// Cache all file contents for Phase 2
staticData._allFileContents = allFiles;

const fileList = allFiles.map(f => f.path);

// Build API surface (exports from each file)
const apiSurface = [];
for (const f of allFiles) {
  if (!f.path.match(/\.(ts|tsx|js|jsx)$/) || f.path.includes('node_modules')) continue;
  const lines = (f.content || '').split('\n');
  const exports = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^export\s+default\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').substring(0, 120));
    } else if (/^export\s+(const|let|var|function|class|interface|type|enum)\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').replace(/=>[\s\S]*$/, '=> ...').substring(0, 150));
    } else if (/^export\s+\{/.test(trimmed)) {
      exports.push(trimmed.substring(0, 150));
    }
  }
  if (exports.length > 0) {
    apiSurface.push(`## ${f.path}\n${exports.join('\n')}`);
  }
}

// Extract dependencies from package.json
let dependencies = {};
let devDependencies = {};
let depNames = [];
for (const f of allFiles) {
  if (f.path === 'package.json' || f.path.endsWith('/package.json')) {
    try {
      const pkg = JSON.parse(f.content);
      dependencies = { ...dependencies, ...(pkg.dependencies || {}) };
      devDependencies = { ...devDependencies, ...(pkg.devDependencies || {}) };
      depNames = [...Object.keys(pkg.dependencies || {}), ...Object.keys(pkg.devDependencies || {})];
    } catch(e) {}
  }
}

// Build research docs string
const depList = Object.entries(dependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
const devDepList = Object.entries(devDependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
let researchDocs = '';
if (depList || devDepList) {
  researchDocs += '## Dependency Manifest\nOnly use packages listed here.\n';
  if (depList) researchDocs += `dependencies:\n${depList}\n`;
  if (devDepList) researchDocs += `devDependencies:\n${devDepList}\n`;
}
if (apiSurface.length > 0) {
  researchDocs += '\n## Project API Surface\nMatch these import/export signatures exactly when importing from project files.\n';
  researchDocs += apiSurface.join('\n\n');
}

// Cache for all downstream phases
staticData._researchDocs = researchDocs;
staticData._projectFileList = fileList;
staticData._projectApiSummary = apiSurface.join('\n');
staticData._projectDeps = depNames;

return [{ json: {
  message,
  project_goal: memory.goal || message,
  project_id: memory.project_id,
  existing_files: fileList,
  api_summary: apiSurface.join('\n'),
  installed_packages: depNames
} }];

const message = $json.message || '';
const existingFiles = $json.existing_files || [];
const apiSummary = $json.api_summary || '';
const installedPkgs = $json.installed_packages || [];
const scrapeData = $json._scrapeData;

let projectContext = '';
if (existingFiles.length > 0) {
  projectContext += `\n\nEXISTING PROJECT FILES (only reference files from this list):\n${existingFiles.join('\n')}\n`;
}
if (apiSummary) {
  projectContext += `\nAPI SURFACE (exports from each file):\n${apiSummary}\n`;
}
if (installedPkgs.length > 0) {
  projectContext += `\nINSTALLED PACKAGES (only reference packages from this list):\n${installedPkgs.join(', ')}\n`;
}

const plannerPrompt = `You are a Senior Software Architect. Your job is to break a coding request into MULTIPLE structured tasks. Each task will be handled by a separate coder with 128K context who can write up to 6 files at once.\n\nOutput a JSON object with ONE field:\n\n"tasks": array of task objects. IMPORTANT: You MUST create multiple tasks. Group files by concern (e.g. styles in one task, frontend components in another, config in another). Each task has:\n- task_id: string like "TASK-001"\n- description: detailed actionable description of what to implement, including specific requirements, color values, component names, API endpoints, and behavior. The coder cannot see the original request — your description is all they get.\n- files: array of exact file paths to create or modify. List EVERY file this task needs — the coder can ONLY write files listed here. For existing projects, prefer modifying files from the EXISTING PROJECT FILES list. For new projects or missing functionality, CREATE new file paths as needed.\n- dependencies: array of task_id strings this task depends on (empty if none)\n- complexity: "low", "medium", or "high"\n\nRULES:\n- Always split work across multiple tasks by concern: styles, components, routes, config, etc.\n- Each task can touch up to 12-15 files. The coder has 128K context and currently uses less than 2% of it — give it MORE work per task. Aim for 2-3 LARGE tasks instead of many small ones. A single task can contain an entire feature (components + hooks + styles + config). Fewer tasks = faster pipeline\n- The description must be SELF-CONTAINED — include ALL details the coder needs\n- For existing projects, reference files from the EXISTING PROJECT FILES list when modifying. You MAY create new files that do not exist yet.
- CRITICAL: For new projects (empty file list), you MUST include a setup task that creates: package.json (with ALL dependencies), index.html, vite.config.js (or next.config.js), tsconfig.json (if TypeScript), tailwind.config.js + postcss.config.js (if using Tailwind), and the main entry point (src/main.jsx or app/layout.tsx). The project MUST be buildable.\n- Detect the project type from the files and packages. If the project is a React/Vite frontend (no Express or backend framework in INSTALLED PACKAGES), focus all tasks on frontend files. Only create server/middleware/API handler tasks if Express or a similar backend framework is in INSTALLED PACKAGES.\n- In each task description, specify the EXACT import/export style each file should use (named vs default) based on the API SURFACE above.\n- The FIRST task should always include project configuration files (package.json, config files, index.html) if they do not already exist. The project MUST compile and run after all tasks complete.
- Output ONLY the raw JSON object: {"tasks": [...]}\n- No markdown, no explanation — ONLY the JSON with tasks`;

let messageContent;
if (scrapeData && scrapeData.screenshot_b64) {
  const cssTokensStr = JSON.stringify(scrapeData.css_tokens, null, 2);
  const domStr = scrapeData.dom_summary || '';
  messageContent = [
    { type: 'image_url', image_url: { url: `data:image/png;base64,${scrapeData.screenshot_b64}` } },
    { type: 'text', text: `${plannerPrompt}\n\nREFERENCE DESIGN (screenshot above):\nCSS Tokens:\n${cssTokensStr}\n\nDOM Structure:\n${domStr}\n\nRequest: ${message}${projectContext}\n\n(Match the visual design, color palette, typography, and layout from the screenshot)` }
  ];
} else if ($('Extract Input').first().json.image_data) {
  const userImage = $('Extract Input').first().json.image_data;
  messageContent = [
    { type: 'image_url', image_url: { url: 'data:image/png;base64,' + userImage } },
    { type: 'text', text: plannerPrompt + '\n\nREFERENCE IMAGE (uploaded by user — replicate this design):\n\nRequest: ' + message + projectContext }
  ];
} else {
  messageContent = `${plannerPrompt}\n\nRequest: ${message}${projectContext}`;
}

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{ role: 'user', content: messageContent }],
    temperature: 0.7,
    top_p: 0.95,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: 32768
  }
}];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/<\/?task>/g, '').trim();
content = content.replace(/\n+(?:Reasoning|Note|Explanation):[\s\S]*/i, '').trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let tasks, planDocument = '';
try {
  const parsed = JSON.parse(content);
  if (Array.isArray(parsed)) {
    tasks = parsed;
  } else {
    tasks = parsed.tasks || [parsed];
    planDocument = parsed.plan_document || '';
  }
} catch (e) {
  // Truncated JSON recovery: extract complete task objects
  const tasksMatch = content.match(/"tasks"\s*:\s*\[/);
  if (tasksMatch) {
    const arrStart = content.indexOf('[', tasksMatch.index);
    let bracketDepth = 0;
    let lastCompleteObj = -1;
    for (let i = arrStart; i < content.length; i++) {
      if (content[i] === '{') bracketDepth++;
      if (content[i] === '}') {
        bracketDepth--;
        if (bracketDepth === 0) lastCompleteObj = i;
      }
    }
    if (lastCompleteObj > arrStart) {
      const recoveredArr = content.substring(arrStart, lastCompleteObj + 1) + ']';
      try {
        tasks = JSON.parse(recoveredArr);
      } catch (e2) {
        tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
      }
    } else {
      tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
    }
  } else {
    tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
  }
}

tasks = tasks.map(t => ({
  ...t,
  files: t.files || [],
  dependencies: t.dependencies || [],
  complexity: t.complexity || 'medium'
}));

return [{ json: { tasks, plan_document: planDocument } }];

// MODIFIED: Absorbs Split Into Chunks. Builds flat (task, chunk) queue.
// Queue is passed through data pipeline (not static data) to avoid stale reads after HTTP nodes.
const tasks = $json.tasks || [];
const planDocument = $json.plan_document || '';
const plannerInput = $('Prepare Planner Input').first().json;
const projectId = plannerInput.project_id;
const projectGoal = plannerInput.project_goal;

// Topological sort
const taskMap = new Map();
tasks.forEach(t => taskMap.set(t.task_id, t));
const inDegree = new Map();
const dependents = new Map();
tasks.forEach(t => {
  inDegree.set(t.task_id, 0);
  dependents.set(t.task_id, []);
});
tasks.forEach(t => {
  const deps = (t.dependencies || []).filter(d => taskMap.has(d));
  inDegree.set(t.task_id, deps.length);
  deps.forEach(d => dependents.get(d).push(t.task_id));
});
const topoQueue = [];
tasks.forEach(t => {
  if (inDegree.get(t.task_id) === 0) topoQueue.push(t.task_id);
});
const sorted = [];
while (topoQueue.length > 0) {
  const id = topoQueue.shift();
  sorted.push(taskMap.get(id));
  for (const dep of (dependents.get(id) || [])) {
    inDegree.set(dep, inDegree.get(dep) - 1);
    if (inDegree.get(dep) === 0) topoQueue.push(dep);
  }
}
if (sorted.length < tasks.length) {
  const sortedIds = new Set(sorted.map(t => t.task_id));
  tasks.forEach(t => { if (!sortedIds.has(t.task_id)) sorted.push(t); });
}

// Flatten into (task, chunk) queue — 2 files per chunk
const chunkSize = 15;
const queue = [];
for (const task of sorted) {
  const taskFiles = task.files || [];
  const chunks = [];
  for (let i = 0; i < taskFiles.length; i += chunkSize) {
    chunks.push(taskFiles.slice(i, i + chunkSize));
  }
  if (taskFiles.length === 0) continue;  // skip tasks with no files assigned
  for (const chunkFiles of chunks) {
    queue.push({
      task,
      chunk_files: chunkFiles,
      project_id: projectId,
      project_goal: projectGoal,
      plan_document: planDocument
    });
  }
}

const staticData = $getWorkflowStaticData('global');
staticData.p2Results = [];
staticData.allTasks = sorted;
staticData._queueTotal = queue.length;
staticData._queueDone = 0;

if (queue.length === 0) {
  return [{ json: { task: { task_id: 'NONE', description: 'No tasks', files: [] }, chunk_files: [], project_id: projectId, project_goal: projectGoal, plan_document: planDocument, _p2Queue: [] } }];
}
// Pass remaining queue items through data pipeline instead of static data
const first = queue[0];
first._p2Queue = queue.slice(1);
return [{ json: first }];

// P2: Stash Context — passes through all fields including _p2Queue for loop control
const staticData = $getWorkflowStaticData('global');
staticData._currentProjectId = $json.project_id;
staticData._currentTaskId = ($json.task || {}).task_id || '';
staticData._currentTask = $json.task || null;
staticData._currentProjectGoal = $json.project_goal || '';
staticData._currentQueue = $json._p2Queue || [];  // snapshot queue for this iteration
return [{ json: {
  task: $json.task,
  chunk_files: $json.chunk_files,
  project_id: $json.project_id,
  project_goal: $json.project_goal,
  plan_document: $json.plan_document,
  _p2Queue: $json._p2Queue || []
} }];

// Builds coder input with FULL project context (not just chunk files)
// The coder has 128K context — feed it everything so it sees the whole picture
const staticData = $getWorkflowStaticData('global');
const stashed = $json;
const chunkFiles = stashed.chunk_files || [];
const allFiles = staticData._allFileContents || [];

// Send ALL project files as context — the coder needs to see CSS classes,
// imports, exports, and component props across the entire project
const existingFiles = allFiles;

// Mark which files are in THIS task's chunk (so coder knows what to output)
const task = { ...(stashed.task || {}) };
if (chunkFiles.length > 0) task.files = chunkFiles;

return [{ json: {
  task,
  existing_files: existingFiles,
  plan_document: stashed.plan_document || '',
  project_goal: stashed.project_goal || '',
  project_id: stashed.project_id,
  research_docs: staticData._researchDocs || ''
} }];

// MODIFIED: Removed retry/feedback logic (that's Phase 4 now)
// Removed hardcoded tech stack, uses positive language
const input = $json;
const planDocument = input.plan_document || '';

let taskDescription = input.task?.description || input.description || '';
if (!taskDescription && input.task?.raw_output) {
  const raw = input.task.raw_output;
  const cleaned = raw.replace(/<\/?task>/g, '').replace(/\n+(?:Reasoning|Note):[\s\S]*/i, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    const list = Array.isArray(parsed) ? parsed : (parsed.tasks || []);
    taskDescription = list.map(t => `${t.task_id}: ${t.description}`).join('\n\n');
  } catch(e) { taskDescription = raw; }
}

const taskFiles = (input.task || {}).files || [];
const filesConstraint = taskFiles.length > 0
  ? '\n\nFILES TO MODIFY (only output these files):\n' + taskFiles.join('\n')
  : '';

const existingFiles = input.existing_files || [];
const existingFilesSection = existingFiles.length > 0
  ? '\n\nFULL PROJECT CONTEXT (all files in the project — read these for context but ONLY output files listed in FILES TO MODIFY):\n' +
    existingFiles.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n')
  : '';

const researchDocs = input.research_docs || '';
const hasDependencyManifest = researchDocs.includes('## Dependency Manifest');
const depRule = hasDependencyManifest
  ? '- CRITICAL: Only use packages found in the Dependency Manifest below. If you need functionality from a package not in the manifest, use built-in browser/Node APIs or the listed packages instead.'
  : '- CRITICAL: No package.json exists yet. Only use packages that are explicitly named in the Task description above. For anything not named, use built-in browser/Node APIs instead.';

const userContent = `Task:\n${taskDescription}${filesConstraint}${existingFilesSection}`;

let systemMessage = `You are a Senior Full-Stack Developer. Output ONLY the files that need to be created or changed. Skip files that are already correct.\n\nFor EACH file you need to create or modify, output EXACTLY this format:\n### path/to/file.ts\n\`\`\`ts\n[complete file content]\n\`\`\`\n\nRULES:\n- Only output files that this task requires you to create or change\n- Output complete file content (not diffs)\n- No explanations, no numbered lists, no prose — ONLY the file blocks\n- Only output files listed in the FILES TO MODIFY section\n- CRITICAL: Implement EXACTLY what the Task specifies. Use the exact text strings, component names, props, and content listed. Never substitute generic placeholders for specified content.\n- ${depRule.replace(/^- /, '')}\n- CRITICAL: Match import styles to the source module. Use named imports ({ X }) for named exports, default imports for default exports. Check the EXISTING PROJECT FILES to confirm each module's export style.\n- Preserve each file's existing export style (named vs default) when modifying it`;

if (planDocument) {
  systemMessage += `\n\nARCHITECTURE REFERENCE (follow this plan):\n${planDocument}`;
}

if (researchDocs) {
  systemMessage += `\n\nPROJECT CONTEXT (from research agent):\n${researchDocs}`;
}

return [{ json: {
  model: $env.CODER_MODEL || 'qwen/qwen3-30b-a3b-2507',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userContent }
  ],
  temperature: 0.1,
  top_p: 0.3,
  top_k: 20,
  min_p: 0.0,
  presence_penalty: 0.0,
  repeat_penalty: 1.05,
  max_tokens: 16384
} }];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) {
  content = content.split('</think>').pop().trim();
}
const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*(?:\.\w[\w.-]*|[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|txt|lock|toml|cfg|ini)|Dockerfile|Makefile|LICENSE|CHANGELOG))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path)) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}
const staticData = $getWorkflowStaticData('global');
const projectId = staticData._currentProjectId || $('Extract Input').first().json.project_id || 'unknown';
const task = staticData._currentTask || {};
const projectGoal = staticData._currentProjectGoal || $('Extract Input').first().json.message || '';
return [{ json: { files, task, project_id: projectId, project_goal: projectGoal } }];

// NEW: Replaces Chunk: Prepare Write
// Simplified write prep + updates _allFileContents cache so later chunks see fresh content
const stashed = $('P2: Stash Context').first().json;
const chunkFiles = stashed.chunk_files || [];
const newFiles = $json.files || [];
const staticData2 = $getWorkflowStaticData('global');
const projectId = $json.project_id || staticData2._currentProjectId || stashed.project_id;

// Include all files the Code Writer produced
let filteredFiles = newFiles;

// Handle package.json merge: preserve existing deps, add new ones
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
for (const newFile of filteredFiles) {
  if (newFile.path === 'package.json' || newFile.path.endsWith('/package.json')) {
    const existing = allFiles.find(f => f.path === newFile.path);
    if (existing) {
      try {
        const existingPkg = JSON.parse(existing.content);
        const newPkg = JSON.parse(newFile.content);
        newPkg.dependencies = { ...(existingPkg.dependencies || {}), ...(newPkg.dependencies || {}) };
        newPkg.devDependencies = { ...(existingPkg.devDependencies || {}), ...(newPkg.devDependencies || {}) };
        newFile.content = JSON.stringify(newPkg, null, 2);
      } catch(e) {}
    }
  }
}

// Update the in-memory file cache so later chunks see fresh content
for (const newFile of filteredFiles) {
  const idx = allFiles.findIndex(f => f.path === newFile.path);
  if (idx >= 0) {
    allFiles[idx] = { path: newFile.path, content: newFile.content };
  } else {
    allFiles.push({ path: newFile.path, content: newFile.content });
  }
}
staticData._allFileContents = allFiles;

if (filteredFiles.length === 0) {
  return [{ json: { project_id: projectId, files: [], _skipWrite: true } }];
}

return [{ json: { project_id: projectId, files: filteredFiles } }];

// P2: Store Result — uses $json like all other Code nodes
const staticData = $getWorkflowStaticData('global');
staticData._queueDone = (staticData._queueDone || 0) + 1;
const total = staticData._queueTotal || 0;
const done = staticData._queueDone;
const remaining = total - done;

const taskId = staticData._currentTaskId || 'unknown';
const writtenFiles = ($json.files_written || $json.files || []).map(f => typeof f === 'string' ? f : (f.path || JSON.stringify(f)));
if (!staticData.p2Results) staticData.p2Results = [];
staticData.p2Results.push({ task_id: taskId, files_written: writtenFiles });


// Status callback to Forge — fire and forget
try {
  const http = require('http');
  const cbBody = JSON.stringify({
    event: 'task_written',
    project_id: staticData._currentProjectId || 'unknown',
    data: { task_id: taskId, files: writtenFiles }
  });
  const cbReq = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  cbReq.on('error', () => {});
  cbReq.write(cbBody);
  cbReq.end();
} catch(e) {}

const remainingQueue = staticData._currentQueue || [];
const isDone = remaining <= 0 || remainingQueue.length === 0;

let nextItem = null;
if (!isDone) {
  nextItem = JSON.parse(JSON.stringify(remainingQueue[0]));
  nextItem._p2Queue = remainingQueue.slice(1);
}

return [{ json: {
  _done: isDone,
  _nextItem: nextItem,
  _remaining: remaining,
  task_id: taskId,
  files_written: writtenFiles
} }];

// NEW: Full-project cross-file review prompt
// Reviewer sees ALL files at once — catches import/export mismatches, type errors, missing deps
const allFiles = $json.files || [];
const staticData = $getWorkflowStaticData('global');
const plannerInput = $('Prepare Planner Input').first().json;
const projectGoal = plannerInput.project_goal || '';
const deps = staticData._projectDeps || [];

// Build tasks summary
const taskSummaries = (staticData.allTasks || []).map(t =>
  `${t.task_id}: ${t.description.substring(0, 200)}`
).join('
');

// Format all files for review
const allFilesFormatted = allFiles
  .filter(f => f.path.match(/\.(ts|tsx|js|jsx|json|css|html)$/) && !f.path.includes('node_modules'))
  .map(f => `### ${f.path}
\`\`\`
${f.content}
\`\`\``)
  .join('

');

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{
      role: 'user',
      content: `You are a Senior Code Reviewer performing a FULL PROJECT REVIEW.
You are reviewing ALL files in the project after all coding tasks have been completed.

Your job is to find cross-file issues that a per-file review would miss:
1. IMPORT/EXPORT MISMATCHES: imports that reference exports that don't exist, wrong import style (named vs default)
