if (content.includes('</think>')) content = content.split('</think>').pop().trim();

// Strip markdown code fences
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

// Try multiple parse strategies
let review;
try {
  // Strategy 1: direct parse (content is pure JSON)
  review = JSON.parse(content);
} catch(e1) {
  try {
    // Strategy 2: extract JSON object with balanced braces
    let depth = 0, start = -1, end = -1;
    for (let i = 0; i < content.length; i++) {
      if (content[i] === '{') { if (depth === 0) start = i; depth++; }
      if (content[i] === '}') { depth--; if (depth === 0) { end = i + 1; break; } }
    }
    if (start >= 0 && end > start) {
      review = JSON.parse(content.substring(start, end));
    } else {
      throw new Error('No balanced JSON found');
    }
  } catch(e2) {
    review = { final_quality: 0, summary: 'Final review parse failed: ' + e2.message, suggestions: [] };
  }
}

// Normalize suggestions format (handle both string[] and {preview, detail}[] )
if (review.suggestions) {
  review.suggestions = review.suggestions.map(s => {
    if (typeof s === 'string') return s;
