} catch(e) {}

return [$input.all()[0]];

// Research: Fetch library docs from Context7 MCP
// Extracts deps from package.json + planner output, fetches relevant docs
const http = require('http');
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
const tasks = $json.tasks || [];

// 1. Extract library names from package.json (if exists)
const libs = new Set();
const pkgFile = allFiles.find(f => f.path === 'package.json');
if (pkgFile) {
  try {
    const pkg = JSON.parse(pkgFile.content);
    for (const dep of Object.keys(pkg.dependencies || {})) libs.add(dep);
    for (const dep of Object.keys(pkg.devDependencies || {})) libs.add(dep);
  } catch(e) {}
}

// 2. Extract from task descriptions (detect common frameworks)
const taskText = tasks.map(t => t.description || '').join(' ').toLowerCase();
const knownLibs = ['react', 'next', 'nextjs', 'vite', 'tailwindcss', 'tailwind', 'express', 'prisma', 'framer-motion', 'heroui', 'zustand', 'zod'];
for (const lib of knownLibs) {
  if (taskText.includes(lib)) libs.add(lib === 'nextjs' ? 'next' : lib === 'tailwind' ? 'tailwindcss' : lib);
}

// Always include react if any jsx/tsx files exist
if (allFiles.some(f => f.path.match(/\.(jsx|tsx)$/))) libs.add('react');

// Filter to top 5 most important (don't fetch docs for every tiny dep)
const priorityLibs = ['react', 'next', 'vite', 'tailwindcss', 'express', 'prisma', 'framer-motion', '@heroui/react'];
const toFetch = [...libs].filter(l => priorityLibs.includes(l)).slice(0, 5);

if (toFetch.length === 0) {
  staticData._researchDocs = '';
  return [{ json: $json }];
}

// 3. Call Context7 MCP for each library
function mcpRequest(sessionId, method, params) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({ jsonrpc: '2.0', method, params, id: Date.now() });
    const req = http.request({
      hostname: 'docky', port: 8811, path: '/mcp', method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        ...(sessionId ? { 'Mcp-Session-Id': sessionId } : {})
      }
    }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        // Parse SSE response
        const lines = data.split('\n');
        for (const line of lines) {
          if (line.startsWith('data: ')) {
            try { resolve(JSON.parse(line.slice(6))); return; }
            catch(e) {}
          }
        }
        resolve({});
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('timeout')); });
    req.write(body);
    req.end();
  });
}

let docs = [];
try {
  // Initialize MCP session
  const initResp = await mcpRequest(null, 'initialize', {
    protocolVersion: '2024-11-05',
    capabilities: {},
    clientInfo: { name: 'eek-go-researcher', version: '1.0' }
  });

  // Extract session ID from response (it's in the HTTP headers, but we can reuse the init)
  // Actually for Streamable HTTP, we need the session from headers. Let's do a raw approach.

  // Get session ID via raw request
  const sessionId = await new Promise((resolve, reject) => {
    const body = JSON.stringify({ jsonrpc: '2.0', method: 'initialize', params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'eek-go', version: '1.0' } }, id: 1 });
    const req = http.request({
      hostname: 'docky', port: 8811, path: '/mcp', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
    }, res => {
      const sid = res.headers['mcp-session-id'];
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => resolve(sid));
    });
    req.on('error', () => resolve(null));
    req.setTimeout(10000, () => { req.destroy(); resolve(null); });
    req.write(body);
    req.end();
  });

  if (!sessionId) {
    staticData._researchDocs = '';
    return [{ json: $json }];
  }

  // Fetch docs for each library
  for (const lib of toFetch) {
    try {
      // Resolve library ID
      const resolveResp = await mcpRequest(sessionId, 'tools/call', {
        name: 'resolve-library-id',
        arguments: { libraryName: lib }
      });
      const resolveText = (resolveResp.result?.content || []).map(c => c.text || '').join('');

      // Extract the first library ID (format: /org/project)
      const idMatch = resolveText.match(/\/[\w.-]+\/[\w.-]+/);
      if (!idMatch) continue;
      const libId = idMatch[0];

      // Get docs
      const docsResp = await mcpRequest(sessionId, 'tools/call', {
        name: 'get-library-docs',
        arguments: { context7CompatibleLibraryID: libId, tokens: 5000, topic: 'setup configuration components hooks API' }
      });
      const docText = (docsResp.result?.content || []).map(c => c.text || '').join('');

      if (docText && docText.length > 100) {
        docs.push(`## ${lib} (${libId})\n${docText.substring(0, 8000)}`);
      }
    } catch(e) {
      // Skip this library, continue with others
    }
  }
} catch(e) {
  // MCP gateway down — continue without research
}

const researchDocs = docs.length > 0
  ? '## Library Documentation (from Context7)\n\n' + docs.join('\n\n---\n\n')
  : '';

staticData._researchDocs = researchDocs;

// Send callback to Forge
try {
  const projectId = staticData._currentProjectId || 'unknown';
  const cbBody = JSON.stringify({
    event: 'research_complete',
    project_id: projectId,
    data: { libraries_fetched: toFetch, doc_count: docs.length }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody);
  req.end();
} catch(e) {}

return [{ json: $json }];

