import React, { useCallback } from 'react';
import { useGameStore } from '../store/gameStore';
import FloatingText from './FloatingText';

const GameArea: React.FC = () => {
  const { addPoop, clickPower } = useGameStore();
  const [floatingTexts, setFloatingTexts] = React.useState<{ id: number; text: string; x: number; y: number }[]>([]);

  const handleClick = useCallback((e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    // Add floating text
    const newTextId = Date.now();
    setFloatingTexts(prev => [...prev, { id: newTextId, text: `+${clickPower}`, x, y }]);

    // Trigger poop addition
    addPoop(clickPower);

    // Remove text after animation completes
    setTimeout(() => {
      setFloatingTexts(prev => prev.filter(text => text.id !== newTextId));
    }, 1000);
  }, [addPoop, clickPower]);

  return (
    <div 
      className="relative w-full h-96 md:h-[500px] bg-black/30 border-2 border-gold rounded-lg shadow-2xl overflow-hidden cursor-pointer transform transition hover:scale-105 active:scale-95"
      onClick={handleClick}
    >
      {/* Toilet Emoji Button */}
      <div className="absolute inset-0 flex items-center justify-center">
        <span className="text-8xl md:text-9xl select-none animate-pulse">🚽</span>
      </div>

      {/* Floating Text Animations */}
      {floatingTexts.map(text => (
        <FloatingText 
          key={text.id} 
          text={text.text} 
          x={text.x} 
          y={text.y} 
        />
      ))}
    </div>
  );
};

