import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { upgrades as upgradeDefinitions } from '../data/upgrades';

interface Upgrade {
  id: string;
  name: string;
  description: string;
  cost: number;
  unlocked: boolean;
}

interface GameState {
  poop: number;
  lifetimePoop: number;
  clickPower: number;
  autoRate: number;
  unlockedUpgrades: string[];
}

type GameActions = {
  addPoop: (amount: number) => void;
  buyUpgrade: (id: string) => void;
};

export const useGameStore = create<GameState & GameActions>()(
  persist(
    (set, get) => ({
      poop: 0,
      lifetimePoop: 0,
      clickPower: 1,
      autoRate: 0,
      unlockedUpgrades: [],
      addPoop: (amount) =>
        set((state) => {
          const newPoop = state.poop + amount;
          const newLifetimePoop = state.lifetimePoop + amount;
          return { poop: newPoop, lifetimePoop: newLifetimePoop };
        }),
      buyUpgrade: (id) => {
        const { unlockedUpgrades, poop } = get();
        const upgradeDef = upgradeDefinitions.find((u) => u.id === id);

        if (!upgradeDef || !upgradeDef.unlocked || poop < upgradeDef.cost) return;

        const updatedUnlockedUpgrades = [...unlockedUpgrades, id];

        set({
          poop: poop - upgradeDef.cost,
          unlockedUpgrades: updatedUnlockedUpgrades,
        });

        // Execute the effect
        const upgrade = upgradeDefinitions.find((u) => u.id === id);
        if (upgrade && upgrade.effect) {
          upgrade.effect(get());
        }
      },
    }),
    {
      name: 'attack-on-toilet-save',
      partialize: (state) => ({
        poop: state.poop,
        lifetimePoop: state.lifetimePoop,
        clickPower: state.clickPower,
        autoRate: state.autoRate,
        unlockedUpgrades: state.unlockedUpgrades,
      }),
    }
  )
);

export interface Upgrade {
  id: string;
  name: string;
  description: string;
  cost: number;
  effect: (state: GameState) => void;
  unlocked: boolean;
}

export interface GameState {
  poop: number;
  lifetimePoop: number;
  clickPower: number;
  autoRate: number;
  upgrades: Upgrade[];
}

