      "preview": "Short 1-sentence title describing the scope of this suggestion",
      "detail": "The full detailed engineering brief — 10-20 sentences with every file path, function name, prop name, and exact change described"
    }
  ]
}

RULES FOR SUGGESTIONS:

Produce exactly 2-3 suggestions. Each suggestion has a "preview" (1 sentence, ~15 words) and a "detail" (full engineering brief).

The "detail" field is what gets sent to the coding pipeline. The pipeline has a 128K context coder that handles 6-8 files per task. Each suggestion's detail should generate 2-4 large tasks.

Suggestion categories (pick 2-3 that apply):
1. CRITICAL FIXES: All bugs, broken imports, wrong props, missing wiring. For EACH broken file: state the path, what's wrong, and the exact fix. Include variable names, prop names, function signatures.
2. MISSING FEATURES: Core functionality that was requested but not implemented. Describe each feature in detail — what component renders it, what state it needs, what hooks/handlers to add, what files to create.
3. UI/UX POLISH & ENHANCEMENTS: Animations, responsive design, accessibility, visual improvements, error states, loading states. Reference specific CSS classes, component names, and design patterns.

Each "detail" should be a DENSE paragraph of 10-20 sentences. It should read like a complete engineering brief — a developer can execute every change from the description alone. Reference specific file paths, function names, prop names, state variables, and CSS classes throughout.

If the project is in great shape (90+), focus suggestions on enhancements: new features, dark mode, localStorage persistence, accessibility, performance optimization.`;

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.3,
    top_p: 0.6,
    max_tokens: 16384
  }
}];

// Parse final review — robust JSON extraction
const msg = ($json.choices && $json.choices[0] && $json.choices[0].message) || {};
let raw = msg.content || '';

// If content is empty/whitespace, try reasoning_content
if (!raw.trim()) raw = msg.reasoning_content || '';

// Strip thinking blocks
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();

// Strip markdown code fences
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

// Try multiple parse strategies
let review;
try {
  // Strategy 1: direct parse (content is pure JSON)
  review = JSON.parse(content);
} catch(e1) {
  try {
    // Strategy 2: extract JSON object with balanced braces
    let depth = 0, start = -1, end = -1;
    for (let i = 0; i < content.length; i++) {
      if (content[i] === '{') { if (depth === 0) start = i; depth++; }
      if (content[i] === '}') { depth--; if (depth === 0) { end = i + 1; break; } }
    }
    if (start >= 0 && end > start) {
      review = JSON.parse(content.substring(start, end));
    } else {
      throw new Error('No balanced JSON found');
    }
  } catch(e2) {
    review = { final_quality: 0, summary: 'Final review parse failed: ' + e2.message, suggestions: [] };
  }
}

// Normalize suggestions format (handle both string[] and {preview, detail}[] )
if (review.suggestions) {
  review.suggestions = review.suggestions.map(s => {
    if (typeof s === 'string') return s;
    if (s && s.preview) return s;
    return String(s);
  });
}

const staticData = $getWorkflowStaticData('global');
staticData._finalReview = review;

// Send callback to Forge
try {
  const http = require('http');
  const projectId = $('Prepare Planner Input').first().json.project_id || 'unknown';
  const cbBody = JSON.stringify({
    event: 'final_review_complete',
    project_id: projectId,
    data: { quality: review.final_quality, summary: review.summary, suggestions: review.suggestions }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback',
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody);
  req.end();
} catch(e) {}

return [{ json: review }];

